import time

def get_ls_result(dir_path: str) -> str:
    try:
        with os.scandir(dir_path) as it:
            entries = list(it)
    except Exception:
        return ""

    if not entries:
        return "total 0\n"

    try:
        rows = []
        total_blocks = 0

        for entry in entries:
            try:
                st = entry.stat(follow_symlinks=False)
            except OSError:
                continue

            total_blocks += st.st_blocks

            mode = stat.filemode(st.st_mode)
            nlink = st.st_nlink

            try:
                owner = pwd.getpwuid(st.st_uid).pw_name
            except KeyError:
                owner = str(st.st_uid)

            try:
                group = grp.getgrgid(st.st_gid).gr_name
            except KeyError:
                group = str(st.st_gid)

            if stat.S_ISCHR(st.st_mode) or stat.S_ISBLK(st.st_mode):
                size = f"{os.major(st.st_rdev)}, {os.minor(st.st_rdev)}"
            else:
                size = str(st.st_size)

            mtime = st.st_mtime
            now = time.time()
            six_months = 15778476
            tm = time.localtime(mtime)
            month = time.strftime("%b", tm)
            day = f"{tm.tm_mday:2d}"
            if mtime > now + six_months or mtime < now - six_months:
                mtime_str = f"{month} {day}  {tm.tm_year}"
            else:
                hour_min = time.strftime("%H:%M", tm)
                mtime_str = f"{month} {day} {hour_min}"

            name = entry.name
            if entry.is_symlink():
                try:
                    target = os.readlink(entry.path)
                    name = f"{name} -> {target}"
                except OSError:
                    pass

            rows.append((mode, nlink, owner, group, size, mtime_str, name))

        if not rows:
            return "total 0\n"

        w_nlink = max(len(str(r[1])) for r in rows)
        w_owner = max(len(r[2]) for r in rows)
        w_group = max(len(r[3]) for r in rows)
        w_size = max(len(str(r[4])) for r in rows)

        total = total_blocks // 2
        lines = [f"total {total}"]
        for mode, nlink, owner, group, size, mtime_str, name in sorted(rows, key=lambda r: r[6]):
            lines.append(
                f"{mode} {nlink:>{w_nlink}} {owner:<{w_owner}} "
                f"{group:<{w_group}} {size:>{w_size}} {mtime_str} {name}"
            )

        return "\n".join(lines) + "\n"
    except Exception:
        return ""

