import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    if isinstance(known_hash, str):
        try:
            known_digest = bytes.fromhex(known_hash)
        except ValueError:
            computed = hashlib.sha256(certificate).hexdigest()
            return len(computed) == len(known_hash) and hmac.compare_digest(computed, known_hash.lower())
    else:
        known_digest = known_hash

    computed = hashlib.sha256(certificate).digest()
    return len(computed) == len(known_digest) and hmac.compare_digest(computed, known_digest)

